INSERT INTO `achievement_locale` (`ID`, `locale`, `Description_lang`, `Title_lang`, `Reward_lang`, `VerifiedBuild`) VALUES
(62773, 'itIT', 'Compi tutte le imprese dei Pescatori dell\'Abisso elencate.', 'Pescatori dell\'Abisso: rivale per Jeju', '', 67186),
(61883, 'itIT', 'Non farti toccare durante il primo minuto di Duello di Decorazioni (x3).', 'Ora non mi vedi...', '', 67186),
(61887, 'itIT', 'Completa tutte le imprese di Duello di Decorazioni.', 'Nascosti di tutto punto', '', 67186),
(61886, 'itIT', 'Sblocca l\'accesso a tutti i potenziamenti in Duello di Decorazioni.', 'Pacchetto completo', '', 67186),
(61882, 'itIT', 'Perdi lo stato Stanato senza farti toccare in Duello di Decorazioni.', 'Elusione totale', '', 67186),
(61881, 'itIT', 'Sii l\'ultimo a non farti toccare come Nascosto della tua squadra in Duello di Decorazioni.', 'Nascosto e introvabile', '', 67186),
(61880, 'itIT', 'Nasconditi e non farti trovare per un minuto e mezzo consecutivo in Duello di Decorazioni.', 'Fa freddo qui all\'ombra', '', 67186),
(61879, 'itIT', 'Vinci un round come Cercatore dopo aver toccato tutti i Nascosti entro due minuti in Duello di Decorazioni.', 'Ti ho preso', '', 67186),
(61878, 'itIT', 'Tocca un personaggio avversario come Guardaboschi Arcano in Duello di Decorazioni.', 'Messo nel sacco', '', 67186),
(61793, 'itIT', 'Tocca un personaggio avversario come Nullificatore in Duello di Decorazioni.', 'Schierato verso il Vuoto', '', 67186),
(61792, 'itIT', 'Tocca un personaggio avversario come Spezzamagie in Duello di Decorazioni.', 'Ti ho beccato!', '', 67186),
(63263, 'itIT', '', '[DNT]Midnight Keystone Myth: Season One Personal Achievement', '', 67186),
(63097, 'itIT', 'Ottieni un Punteggio Mitica+ di almeno 3.400 durante la Stagione 1 di Midnight.', 'Mito delle Chiavi di Midnight: Stagione 1', 'Titolo: il Contendente Ombrale e Oggetto: Sella Senza Tempo', 67186),
(61594, 'itIT', 'Completa una spedizione Mitica+ nella Vetta dei Cieli con il miglior tempo della regione.', 'Vincitore delle Chiavi: Vetta dei Cieli', '', 67186),
(61593, 'itIT', 'Completa una spedizione Mitica+ nel Seggio del Triumvirato con il miglior tempo della regione.', 'Vincitore delle Chiavi: Seggio del Triumvirato', '', 67186),
(61592, 'itIT', 'Completa una spedizione Mitica+ nella Fossa di Saron con il miglior tempo della regione.', 'Vincitore delle Chiavi: Fossa di Saron', '', 67186),
(61591, 'itIT', 'Completa una spedizione Mitica+ nell\'Accademia di Algeth\'ar con il miglior tempo della regione.', 'Vincitore delle Chiavi: Accademia di Algeth\'ar', '', 67186),
(61590, 'itIT', 'Completa una spedizione Mitica+ nel Pinnacolo dei Ventolesto con il miglior tempo della regione.', 'Vincitore delle Chiavi: Pinnacolo dei Ventolesto', '', 67186),
(61589, 'itIT', 'Completa una spedizione Mitica+ nella Punta del Nexus Xenas con il miglior tempo della regione.', 'Vincitore Eroe delle Chiavi: Punta del Nexus Xenas', '', 67186),
(61588, 'itIT', 'Completa una spedizione Mitica+ nelle Caverne di Maisara con il miglior tempo della regione.', 'Vincitore delle Chiavi: Caverne di Maisara', '', 67186),
(61587, 'itIT', 'Completa una spedizione Mitica+ nella Terrazza dei Magistri con il miglior tempo della regione (Midnight).', 'Vincitore delle Chiavi: Terrazza dei Magistri (Midnight)', '', 67186),
(61259, 'itIT', 'Termina la Stagione 1 delle Mitiche+ di Midnight con un Punteggio Mitica+ tra i primi 0,1% di tutti i giocatori nella tua regione.', 'Eroe Ombrale: Stagione 1 di Midnight', 'Titolo: l\'Eroe Ombrale', 67186),
(61253, 'itIT', 'Completa tutte le spedizioni Mitiche+ entro il tempo limite con una Chiave del Potere di livello 30 durante la Stagione 1 di Midnight.', 'Stagione 1 di Midnight: Chiave del Potere Resiliente 30', 'Le Chiavi del Potere non scenderanno al di sotto del livello 30 durante la Stagione 1 di Midnight.', 67186),
(61252, 'itIT', 'Completa tutte le spedizioni Mitiche+ entro il tempo limite con una Chiave del Potere di livello 29 durante la Stagione 1 di Midnight.', 'Stagione 1 di Midnight: Chiave del Potere Resiliente 29', 'Le Chiavi del Potere non scenderanno al di sotto del livello 29 durante la Stagione 1 di Midnight.', 67186),
