(12009, 'itIT', 'Sconfiggi L\'ura al Seggio del Triumvirato con tutti i personaggi affetti da Oscurità Devastante in modalità Mitica.', 'Il lato più oscuro', '', 67186),
(12005, 'itIT', 'Fai in modo che Zannacupa distrugga 4 Globi del Vuoto Sigillati usando Agguato dell\'Ombra e sconfiggi Saprish al Seggio del Triumvirato in modalità Mitica.', 'Uno sfogo necessario', '', 67186),
(12004, 'itIT', 'Evoca Urjad dal Reame del Vuoto tramite Squarcio del Vuoto, quindi sconfiggi lui e Zuraal l\'Asceso al Seggio del Triumvirato in modalità Mitica.', 'Benvenuti nel Vuoto', '', 67186),
(9036, 'itIT', 'Sconfiggi l\'Alta Saggia Viryx a Vetta dei Cieli in modalità Eroica senza uccidere alcun Costrutto dello Scudo.', 'Monomania', '', 67186),
(9035, 'itIT', 'Durante lo scontro con Rukhran a Vetta dei Cieli in modalità Eroica, fai in modo che tre Pile di Cenere diano vita a delle Fenici Infuocate contemporaneamente.', 'Tre soli', '', 67186),
(9034, 'itIT', 'Sconfiggi il Costrutto Potenziato a Vetta dei Cieli in modalità Eroica.', 'Ingrandire e potenziare', '', 67186),
(9033, 'itIT', 'Sconfiggi Ranjit a Vetta dei Cieli in modalità Eroica senza subire danni dalle seguenti abilità: Lama Volteggiante, Muro di Lame Ventose, Quattro Venti e Chiarore.', 'Pronto per le incursioni IV', '', 67186),
(4525, 'itIT', 'Supera il tunnel che conduce al Signore della Piaga Tirannus nella Fossa di Saron in modalità Eroica al primo tentativo senza che alcun giocatore subisca danni dalle stalattiti.', 'Non guardare in alto', '', 67186),
(4524, 'itIT', 'Sconfiggi il Mastro Forgiatore Gargelo nella Fossa di Saron in modalità Eroica prima che qualunque giocatore raggiunga 11 accumuli di Permagelo.', 'Rivoluzione numero 11', '', 67186),
