INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'itIT', 'Nucleo del Vuoto Nebuloso', 'Trasmutabile in equipaggiamenti potenti dopo aver sconfitto grandi nemici nelle incursioni della Stagione 1 di Midnight o completando spedizioni Mitiche+, Scorribande Fruttuose e Cacce alla Preda in modalità Incubo.', 67186),
(3347, 'itIT', 'Emblema dell\'Alba del Mito', 'Si usa per potenziare l\'equipaggiamento Mito durante la Stagione 1 di Midnight fino ai livelli 276-289. \n\nSe si usa per l\'artigianato, in base alla qualità, imposta il livello oggetto dell\'oggetto risultante a 272-285.\n\nSi ottiene dalle attività seguenti:\n\n- Pinnacolo del Vuoto, Frattura del Sogno, Marcia su Quel\'Danas in modalità Mitica\n- Spedizioni Mitiche+ (da +9 e superiori)', 67186),
(3346, 'itIT', 'Emblema dell\'Alba dell\'Eroe', 'Si usa per potenziare l\'equipaggiamento Eroe durante la Stagione 1 di Midnight fino ai livelli 263-276. Si ottiene dalle attività seguenti:\n\n- Pinnacolo del Vuoto, Frattura del Sogno, Marcia su Quel\'Danas in modalità Eroica\n- Spedizioni Mitiche+ (da +4 a +8)\n- Scorribande (Grado 11)\n- Bottino del Cacciatore di Tesori (Grado 8+)\n- Cacce alla Preda (Incubo)', 67186),
(3345, 'itIT', 'Emblema dell\'Alba dell\'Eroe', 'Si usa per potenziare l\'equipaggiamento Eroe durante la Stagione 1 di Midnight fino ai livelli 263-276.\n\nSe si usa per l\'artigianato, in base alla qualità, imposta il livello oggetto dell\'oggetto risultante a 259-272.\n\nSi ottiene dalle attività seguenti:\n\n- Pinnacolo del Vuoto, Frattura del Sogno, Marcia su Quel\'Danas in modalità Eroica\n- Spedizioni Mitiche+ (da +4 a +8)\n- Scorribande (Grado 11)\n- Bottino del Cacciatore di Tesori (Grado 8+)\n- Cacce alla Preda (Incubo)', 67186),
(3344, 'itIT', 'Emblema dell\'Alba del Campione', 'Si usa per potenziare l\'equipaggiamento Campione durante la Stagione 1 di Midnight fino ai livelli 250-263. Si ottiene dalle attività seguenti:\n\n- Eventi esterni settimanali\n- Pinnacolo del Vuoto, Frattura del Sogno, Marcia su Quel\'Danas in modalità Normale\n- Spedizioni stagionali Mitiche\n- Spedizioni Mitiche+ (+2 e +3)\n-Scorribande (Gradi 7-10)\n- Bottino del Cacciatore di Tesori (Gradi 6 e 7)\n- Cacce alla Preda (Incubo)', 67186),
(3343, 'itIT', 'Emblema dell\'Alba del Campione', 'Si usa per potenziare l\'equipaggiamento Campione durante la Stagione 1 di Midnight fino ai livelli 250-263. Si ottiene dalle attività seguenti:\n\n- Eventi esterni settimanali\n- Pinnacolo del Vuoto, Frattura del Sogno, Marcia su Quel\'Danas in modalità Normale\n- Spedizioni stagionali Mitiche\n- Spedizioni Mitiche+ (+2 e +3)\n-Scorribande (Gradi 7-10)\n- Bottino del Cacciatore di Tesori (Gradi 6 e 7)\n- Cacce alla Preda (Incubo)', 67186),
(3342, 'itIT', 'Emblema dell\'Alba del Veterano', 'Si usa per potenziare l\'equipaggiamento Veterano durante la Stagione 1 di Midnight fino ai livelli 237-250. Si ottiene dalle attività seguenti:\n\n- Eventi esterni ripetibili\n- Pinnacolo del Vuoto, Frattura del Sogno, Marcia su Quel\'Danas in modalità Ricerca delle Incursioni\n- Spedizioni stagionali Eroiche\n- Scorribande (Gradi 5 e 6)\n- Bottino del Cacciatore di Tesori (Gradi 4 e 5)\n- Cacce alla Preda (Difficile)', 67186),
(3341, 'itIT', 'Emblema dell\'Alba del Veterano', 'Si usa per potenziare l\'equipaggiamento Veterano durante la Stagione 1 di Midnight fino ai livelli 237-250.\n\nSe si usa per l\'artigianato, in base alla qualità, imposta il livello oggetto dell\'oggetto risultante a 233-246.\n\nSi ottiene dalle attività seguenti:\n\n- Eventi esterni ripetibili\n- Pinnacolo del Vuoto, Frattura del Sogno, Marcia su Quel\'Danas in modalità Ricerca delle Incursioni\n- Spedizioni stagionali Eroiche\n- Scorribande (Gradi 5 e 6)\n- Bottino del Cacciatore di Tesori (Gradi 4 e 5)\n- Cacce alla Preda (Difficile)', 67186),
(3418, 'itIT', 'Nucleo del Vuoto Nebuloso', 'Trasmutabile in equipaggiamenti potenti dopo aver sconfitto grandi nemici nelle incursioni della Stagione 1 di Midnight o completando spedizioni Mitiche+, Scorribande Fruttuose e Cacce alla Preda in modalità Incubo.', 67186),
(3391, 'itIT', 'Emblema dell\'Alba dell\'Avventuriero', 'Si usa per potenziare l\'equipaggiamento Avventuriero durante la Stagione 1 di Midnight fino ai livelli 224-237. Si ottiene dalle attività seguenti:\n\n- Eventi esterni ripetibili\n- Scorribande (Grado 4)\n- Cacce alla Preda (Normale)', 67186),
(3383, 'itIT', 'Emblema dell\'Alba dell\'Avventuriero', 'Si usa per potenziare l\'equipaggiamento Avventuriero durante la Stagione 1 di Midnight fino ai livelli 224-237.\n\nSe si usa per l\'artigianato, in base alla qualità, imposta il livello oggetto dell\'oggetto risultante a 220-233.\n\nSi ottiene dalle attività seguenti:\n\n- Eventi esterni ripetibili\n- Scorribande (Grado 4)\n- Cacce alla Preda (Normale)', 67186),
(3348, 'itIT', 'Emblema dell\'Alba del Mito', 'Si usa per potenziare l\'equipaggiamento Mito durante la Stagione 1 di Midnight fino ai livelli 276-289. Si ottiene dalle attività seguenti:\n\n- Pinnacolo del Vuoto, Frattura del Sogno, Marcia su Quel\'Danas in modalità Eroica\n- Spedizioni Mitiche+ (+9 e superiori)', 67186);
