INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'itIT', 'Difensori', '$bullet;L\'Accumulatore si rifornisce dal cumulo di risorse più vicino durante |cFF2959D3|Hspell:1235072|h[Misure Ingegnose]|h|r.\n$bullet;I Funghi Marci applicano |cFF2959D3|Hspell:1234846|h[Spore Tossiche]|h|r al contatto, impedendo lo scoppio in un\'|cFF2959D3|Hspell:1245593|h[Esplosione Putrida]|h|r.\n$bullet;|cFF2959D3|Hspell:1234681|h[Grido Vorace]|h|r e |cFF2959D3|Hspell:1235125|h[Grido Vigoroso]|h|r infliggono ingenti danni a tutti i personaggi.', 67186),
(32669, 'itIT', 'Sommario', 'L\'Accumulatore impedisce a tutti i costi che le sue riserve vengano saccheggiate, lanciando |cFF2959D3|Hspell:1235072|h[Misure Ingegnose]|h|r quando raggiunge il 90%, il 60% e il 30% di salute restante e potenziando una delle sue abilità.\n\nQuando raggiunge 100 energia, lancia |cFF2959D3|Hspell:1234233|h[Rifornimenti Avariati]|h|r in tutta l\'arena, facendo crescere dei Funghi Marci per 12 s. Al contatto, applicano |cFF2959D3|Hspell:1234846|h[Spore Tossiche]|h|r e distruggono i funghi, impedendo l\'|cFF2959D3|Hspell:1245593|h[Esplosione Putrida]|h|r.', 67186),
(31527, 'itIT', 'Merce Proibita', 'Un carico destinato a restare lontano da occhi indiscreti. Fornisce un\'eccellente copertura.', 67186),
(31282, 'itIT', 'Difensore', '$bullet;Kystia rende Vilmordino ostile ai personaggi con |cFF2959D3|Hspell:1230289|h[Infusione Illecita]|h|r.\n$bullet;Evitare |cFF2959D3|Hspell:1253811|h[Vilspruzzo]|h|r di Vilmordino.\n$bullet;Interrompere |cFF2959D3|Hspell:1264095|h[Immagini Speculari]|h|r di Kystia.', 67186),
(31281, 'itIT', 'Guaritori', '$bullet;Kystia rende Vilmordino ostile ai personaggi con |cFF2959D3|Hspell:1230289|h[Infusione Illecita]|h|r.\n$bullet;Evitare |cFF2959D3|Hspell:1253811|h[Vilspruzzo]|h|r di Vilmordino.\n$bullet; Kystia infligge ingenti danni a tutti i personaggi mentre è |cFF2959D3|Hspell:1265412|h[Destabilizzata]|h|r.', 67186),
(31280, 'itIT', 'Assaltatori', '$bullet;Kystia rende Vilmordino ostile ai personaggi con |cFF2959D3|Hspell:1230289|h[Infusione Illecita]|h|r.\n$bullet;Evitare |cFF2959D3|Hspell:1253811|h[Vilspruzzo]|h|r di Vilmordino.\n$bullet;Interrompere |cFF2959D3|Hspell:1264095|h[Immagini Speculari]|h|r di Kystia.', 67186),
(35862, 'itIT', 'Section 18', '', 67186),
(35353, 'itIT', 'Sezione 17', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'itIT', 'Sezione 17', '', 67186),
(34733, 'itIT', 'Inganno di Xal\'atath', 'Xal\'atath tradisce i personaggi, revocando i suoi patti e facendo in modo che le morti sottraggano 15 s al tempo restante.', 67186),
(34732, 'itIT', 'Potenziamento', 'Aumenta la salute e i danni inflitti dai nemici che non sono boss del 20%.', 67186),
(34731, 'itIT', 'Tirannia', 'Aumenta la salute dei boss del 25%. Aumenta i danni inflitti dai boss e dai suoi servitori fino al 15%.', 67186),
(34730, 'itIT', 'Tirannia e Potenziamento', 'Questi modificatori potenziano ulteriormente i nemici nelle spedizioni Mitiche+. Uno si attiva al livello 7 della modalità Mitica e l\'altro al livello 10 della modalità Mitica, cambiando settimanalmente.', 67186),
(34727, 'itIT', 'Patto di Xal\'atath: Voracità', '', 67186),
(34725, 'itIT', 'Patto di Xal\'atath: Vincolato dal Vuoto', '', 67186),
(34722, 'itIT', 'Patto di Xal\'atath: Pulsar', '', 67186),
(34720, 'itIT', 'Mitica livello 6', '$bullet;|cFF2959D3|Hspell:1284818|h[Guida di Lindormi]|h|r viene rimossa.\n\nI personaggi che sono specializzati come difensori possono parlare con Lindormi vicino al portale dei Flussi Temporali o alla fine di una spedizione Mitica+ per ottenere |cFF2959D3|Hspell:1295986|h[Bagliore di Lindormi]|h|r, che continua a evidenziare le forze nemiche.', 67186),
(35809, 'itIT', 'Section 158', '', 67186),
(35491, 'itIT', 'Sezione 69', '', 67186),
(35490, 'itIT', 'Sezione 70', '', 67186),
(35489, 'itIT', 'Sezione 76', '', 67186),
