INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'itIT', 'Salve!\n\nContempla la meraviglia di questo dominio traboccante di ABBONDANZA GLORIOSA! Essa dilaga, avanza e rifiuta ogni contenimento.\n\nLa tua devozione verso il divino merita un piccolo gesto di benevolenza. Questa volta, sotto forma di Abbondanza Pura.\n\nSappi che alcune offerte, come Vitalità Fusa, ora compariranno anche presso altri mercanti. Qualora le tue avventure ti conducessero nei pressi degli Abissi di Zul\'aman, li incontrerai sicuramente.\n\nA te, raccolti cospicui.\n\n- Dundun, Loa dell\'Abbondanza', 67186);
