INSERT INTO `trait_definition_locale` (`ID`, `locale`, `OverrideName_lang`, `OverrideSubtext_lang`, `OverrideDescription_lang`, `VerifiedBuild`) VALUES
(137688, 'itIT', 'Multipla e Meticolosa', '', 'Migliora le matrici d\'Incantamento, aumentando la probabilità di produrre oggetti aggiuntivi quando si creano illusioni o consumabili. Inoltre, fornisce +$ev1 $en1 per ogni punto in questa specializzazione.', 67186),
(137685, 'itIT', '', '', 'Creazione Multipla fornisce fino al +$ev1% di prodotti aggiuntivi quando si creano consumabili.', 67186),
(137681, 'itIT', '', '', 'Creazione Multipla fornisce fino al +$ev1% di prodotti aggiuntivi quando si creano consumabili.', 67186),
(133669, 'itIT', '', '', ' +$ev1 $en1 quando si creano leghe.|n|n Sblocca l\'abilità di usare i Reagenti di Finitura quando si creano leghe.', 67186);
